import * as React from 'react';
import { ImageViewer } from '..';
import { Button, useEventCallback } from '../..';
export default {
  title: 'Components/ImageViewer/临时示例',
  component: ImageViewer,
};

export const ImageViewerDemo = () => {
  const [visible, setVisible] = React.useState(false);

  const clickBtn = useEventCallback(() => {
    setVisible(true);
  });

  return (
    <>
      <Button onClick={clickBtn}>点击查看图片</Button>
      <ImageViewer
        images={[
          {
            src: 'https://lf3-static.bytednsdoc.com/obj/eden-cn/nuhpebn/universe-design/image-viewer-sample-1.jpg',
          },
          {
            src: 'https://placeholder.com/300x300',
          },
          {
            src: 'https://placeholder.com/2000x300',
          },
          {
            src: 'https://placeholder.com/300x2000',
          },
          {
            src: 'https://placeholder.com/2000x2000',
          },
          {
            src: 'invalid',
          },
        ]}
        visible={{
          value: visible,
          onChange: setVisible,
        }}
      />
    </>
  );
};
